    /**
     * Escapes HTML characters to prevent injection.
     *
     * @param input The string to escape.
     * @return The escaped string, or empty string if input is null.
     */
    private String escapeHtml(String input) {
        if (input == null) {
            return "";
        }
        return input.replace("&", "&amp;")
